code = """import json
import re

# Load the Swift files data
swift_files_path = locals().get('var_functions.query_db:23')
if isinstance(swift_files_path, str):
    with open(swift_files_path, 'r') as f:
        swift_files = json.load(f)
else:
    swift_files = swift_files_path

# Load Swift repos data
swift_repos_path = locals().get('var_functions.query_db:22')
if isinstance(swift_repos_path, str):
    with open(swift_repos_path, 'r') as f:
        swift_repos = json.load(f)
else:
    swift_repos = swift_repos_path

# Function to extract copy count
def extract_copy_count(description):
    patterns = [
        r'duplicated (\d+) time',
        r'appearing (\d+) time',
        r'copied (\d+) time',
        r'repeated (\d+) time',
        r'seen (\d+) time'
    ]
    
    for pattern in patterns:
        match = re.search(pattern, description, re.IGNORECASE)
        if match:
            return int(match.group(1))
    return 0

# Find the most frequently copied file
most_copied = None
max_copies = 0

for file_info in swift_files:
    copy_count = extract_copy_count(file_info['repo_data_description'])
    if copy_count > max_copies:
        max_copies = copy_count
        most_copied = {
            'id': file_info['id'],
            'copy_count': copy_count,
            'repo_name': file_info['sample_repo_name'],
            'path': file_info['sample_path'],
            'description': file_info['repo_data_description']
        }

# Get all Swift repo names set
swift_repo_names = {repo['repo_name'] for repo in swift_repos}

# Verify if the repository is a Swift repository
is_swift_repo = most_copied['repo_name'] in swift_repo_names if most_copied else False

print('__RESULT__:')
print(json.dumps({
    "most_copied_file": most_copied,
    "is_swift_repository": is_swift_repo,
    "total_swift_repos_checked": len(swift_repo_names),
    "total_swift_files_processed": len(swift_files)
}))"""

